mapper.select:
SELECT DATE_FORMAT(stat_date, '%Y-%m-%d') AS date, SUM(tokens_input) AS tokensInput, SUM(tokens_output) AS tokensOutput, SUM(tokens_total) AS tokensTotal, SUM(call_count) AS callCount FROM ai_token_usage_daily
AND stat_date BETWEEN #{startDate} AND #{endDate} AND model_name = #{modelName} AND module_key = #{moduleKey}
GROUP BY stat_date ORDER BY stat_date ASC

SELECT
    model_name AS modelName,
    SUM(tokens_total) AS tokensTotal,
    SUM(call_count) AS callCount
FROM ai_token_usage_daily

    AND stat_date BETWEEN #{startDate} AND #{endDate}
    AND model_name = #{modelName}
    AND module_key = #{moduleKey}

GROUP BY model_name
ORDER BY tokensTotal DESC

SELECT d.scene_id AS sceneId, s.name AS sceneName, SUM(d.call_count) AS callCount, SUM(d.tokens_total) AS tokensTotal FROM ai_token_usage_daily d LEFT JOIN ai_scene s ON d.scene_id = s.id
AND d.stat_date BETWEEN #{startDate} AND #{endDate} AND d.scene_id IS NOT NULL AND d.model_name = #{modelName} AND d.module_key = #{moduleKey}
GROUP BY d.scene_id, s.name ORDER BY callCount DESC

SELECT model_name AS modelName, SUM(call_count) AS callCount, SUM(tokens_input) AS tokensInput, SUM(tokens_output) AS tokensOutput, SUM(tokens_total) AS tokensTotal, SUM(total_cost_yuan) AS totalCostYuan, ROUND(SUM(total_duration_ms) / NULLIF(SUM(call_count), 0)) AS avgDurationMs FROM ai_token_usage_daily
AND stat_date BETWEEN #{startDate} AND #{endDate} AND model_name = #{modelName} AND module_key = #{moduleKey}
GROUP BY model_name ORDER BY totalCostYuan DESC
